css:
/* Remove Anti-aliasing */
* { -webkit-font-smoothing: none !important; font-smooth: never !important; }
/* Command Window Style for Panels */
.bg-theme-surface, .card, .modal-content {
  background-color: #000 !important;
  border: 2px solid #fff !important;
  border-radius: 4px !important;
  box-shadow: 0 0 0 2px #000, 0 0 0 4px #fff, 6px 6px 0px rgba(0,0,0,0.8) !important;
  margin: 4px;
}
/* Triangle Cursor for Active Menu */
.skin-sidebar-item.active { position: relative; border: none !important; }
.skin-sidebar-item.active::before { content: '▶'; position: absolute; left: 8px; color: #fff; font-size: 1.2rem; }
.skin-sidebar-item.active span { padding-left: 12px; color: #ffff00 !important; }
/* Buttons */
.btn-primary {
  background: #fff !important; color: #000 !important;
  border: 2px solid #fff !important; box-shadow: none !important;
}
.btn-primary:hover { background: #ffff00 !important; }
.btn-secondary { background: #000 !important; border: 2px solid #fff !important; color: #fff !important; }
.btn-secondary:hover { color: #ffff00 !important; border-color: #ffff00 !important; }
